parameters.jsCode:
const items = $input.all();

const output = [];

for (const item of items) {
  const behavior = item.json.behavior;
  const results = item.json.data?.Get?.MitreAttackNomic || [];

  for (const r of results) {
    output.push({
      json: {
        behavior,
        attack_id: r.attack_id,
        name: r.name,
        tactic: r.tactic,
        content: r.content
      }
    });
  }
}

return output;

const events = $json.events || [];

let keyEvents = [];
let lastEventType = null;

events.forEach((e, idx) => {
  // Compose a details string from expert messages
  let expertDetails = "";
  if (e.expert_messages && e.expert_messages.length > 0) {
    expertDetails = e.expert_messages
      .map(m => `[${m.flag}] ${m.message} (Severity ${m.severity_normalized}, Group ${m.group_label})`)
      .join("; ");
  }

  const currentEventType = e.event_type || "unknown";

  // Include first, last, or changed event_type
  if (idx === 0 || idx === events.length - 1 || currentEventType !== lastEventType) {
    keyEvents.push(`${e.timestamp_human} EventType=${currentEventType} Details=${expertDetails}`);
    lastEventType = currentEventType;
  }
});

return [
  {
    json: {
      key_events: keyEvents
    }
  }
];

let ips = new Set();
let ports = new Set();
let flagsSet = new Set();
let eventTypes = new Set();
let severityCounts = {};
let groupCounts = {};
let users = new Set();  // Likely empty for PCAPs
let events = [];

let flagCounts = {
  syn: 0,
  fin: 0,
  rst: 0
};

for (const item of $input.all()) {
  const chunks = item.json?.chunk || [];

  for (const chunkItem of chunks) {
    const packet = chunkItem.json;
    if (!packet) continue;

    // IPs and ports
    if (packet.src_ip) ips.add(packet.src_ip);
    if (packet.dst_ip) ips.add(packet.dst_ip);
    if (packet.src_port) ports.add(packet.src_port);
    if (packet.dst_port) ports.add(packet.dst_port);

    // Flags
    if (packet.flags) flagsSet.add(packet.flags);

    // Event types
    if (packet.event_type) eventTypes.add(packet.event_type);

    // Count SYN/FIN/RST
    if (packet.is_syn) flagCounts.syn++;
    if (packet.is_fin) flagCounts.fin++;
    if (packet.is_rst) flagCounts.rst++;

    // Expert messages
    if (Array.isArray(packet.expert_messages)) {
      packet.expert_messages.forEach(e => {
        if (e.severity_normalized != null) {
          severityCounts[e.severity_normalized] = (severityCounts[e.severity_normalized] || 0) + 1;
        }
        if (e.group_label) {
          groupCounts[e.group_label] = (groupCounts[e.group_label] || 0) + 1;
        }
      });
    }

    // Keep each packet as an event
    events.push(packet);
  }
}

return [{
  json: {
    ips: [...ips],
    users: [...users],
    ports: [...ports],
    flags: [...flagsSet],
    event_types: [...eventTypes],
    flag_counts: flagCounts,
    severity_counts: severityCounts,
    group_counts: groupCounts,
    events
  }
}];

const logs = $json.logs || $input.all().map(item => item.json);

if (!logs.length) {
    return [{ json: { behaviors: [], message: "No logs provided" } }];
}

//Check Events within a small time frame
function withinWindow(events, seconds = 60) {
    if (events.length < 2) return false;

    const sorted = events
        .map(e => e.epoch)
        .filter(Boolean)
        .sort((a, b) => a - b);

    return (sorted[sorted.length - 1] - sorted[0]) <= seconds;
}

//Group IPs
const bySrcIP = {};
const byDstIP = {};

for (const log of logs) {
    if (log.src_ip) {
        if (!bySrcIP[log.src_ip]) bySrcIP[log.src_ip] = [];
        bySrcIP[log.src_ip].push(log);
    }

    if (log.dst_ip) {
        if (!byDstIP[log.dst_ip]) byDstIP[log.dst_ip] = [];
        byDstIP[log.dst_ip].push(log);
    }
}

//Compute metrics
function computeMetrics(events) {
    const dstIPs = new Set();
    const dstPorts = new Set();

    let syn = 0, fin = 0, rst = 0;

    for (const e of events) {
        if (e.dst_ip) dstIPs.add(e.dst_ip);
        if (e.dst_port) dstPorts.add(e.dst_port);

        if (e.is_syn) syn++;
        if (e.is_fin) fin++;
        if (e.is_rst) rst++;
    }

    return {
        total: events.length,
        unique_dst_ips: dstIPs.size,
        unique_dst_ports: dstPorts.size,
        syn,
        fin,
        rst
    };
}

// =====================================================
// RULES
// =====================================================
const rules = [

    //Detect network scans
    {
        name: "Repeated connections to same port",
        condition: (events) => {
            const portMap = {};

            for (const e of events) {
                const key = e.dst_port;
                if (!portMap[key]) portMap[key] = [];
                portMap[key].push(e.epoch);
            }

            for (const port in portMap) {
                const times = portMap[port].sort((a, b) => a - b);

                let count = 1;

                for (let i = 1; i < times.length; i++) {
                    if (times[i] - times[i - 1] <= 60) {
                        count++;
                        if (count >= 5 && withinWindow(events, 60)) {
                            return true;
                        }
                    } else {
                        count = 1;
                    }
                }
            }

            return false;
        },
        message: () => 'network_scan: repeated connections to same destination port within a limited time frame'
    },

    //Additional scanning detection
    {
        name: "Network scanning behavior",
        condition: (events) => {
            const m = computeMetrics(events);

            return (
                m.unique_dst_ips >= 10 &&
                m.unique_dst_ports >= 10 &&
                m.total < 500
            );
        },
        message: () => `Network scanning behavior detected`
    },

    //Detect anomalous session termination
    {
        name: "Abnormal session termination",
        condition: (events) =>
            events.filter(e => e.is_rst).length >= 3,
        message: () => 'connection_termination: TCP sessions ending with RST flags observed'
    },

    //Detect multiple protocols
    {
        name: "Multiple protocols observed",
        condition: (events) =>
            new Set(events.map(e => e.protocol)).size >= 2,
        message: () => `protocol_diversity: multiple transport and/or application protocols used`
    },

    //Detect DDoS
    {
        name: "Potential DDoS behavior",
        condition: (events) => {
            const m = computeMetrics(events);
            const synRatio = m.syn / (m.total || 1);

            return (
                m.total >= 50 &&
                m.unique_dst_ips <= 2 &&
                synRatio >= 0.7 &&
                withinWindow(events, 120)
            );
        },
        message: () =>
          'ddos_behavior: high-volume SYN traffic toward limited destination'
    },



    //Protocol Anomalies
    {
        name: "Protocol anomaly presence",
        condition: (events) =>
            events.some(e => e.protocol_anomaly === true),
        message: () => 'Protocol structure anomalies detected'
    }
];

//Evaluate
const behaviors = [];

// Source-based evaluation
for (const rule of rules) {
    for (const ip in bySrcIP) {
        const events = bySrcIP[ip].sort((a, b) => a.epoch - b.epoch);

        if (rule.condition(events)) {
            behaviors.push(rule.message());
        }
    }
}

// Destination-based DDoS confirmation
for (const ip in byDstIP) {
    const events = byDstIP[ip].sort((a, b) => a.epoch - b.epoch);

    const m = computeMetrics(events);
    const synRatio = m.syn / (m.total || 1);

    if (
        m.total >= 50 &&
        m.unique_dst_ips <= 2 &&
        synRatio >= 0.7 &&
        withinWindow(events, 120)
    ) {
        behaviors.push(`Potential DDoS flood targeting ${ip}`);
    }
}

//Remove duplicates
const uniqueBehaviors = [...new Set(behaviors)];

//Create output
return [
    {
        json: {
            behaviors: uniqueBehaviors,
            logsCount: logs.length,
            sources: Object.keys(bySrcIP).length,
            targets: Object.keys(byDstIP).length
        }
    }
];

const data = $json;

// Build event text for LLM
const eventsText = (data.events || []).map((e, i) => {
  const notes = e.expert_messages?.map(m => 
    `${m.message} [${m.group_label}, severity ${m.severity_normalized}]`
  ).join("; ") || "No notes";

  return `${i+1}. Event: ${e.event_type || "Unknown"}
  Source: ${e.src_ip || "Unknown"}:${e.src_port || "Unknown"}
  Destination: ${e.dst_ip || "Unknown"}:${e.dst_port || "Unknown"}
  Protocol: ${e.protocol || "Unknown"}
  Flags: ${e.flags || ""}
  Notes: ${notes}
  Timestamp: ${e.timestamp_human || e.timestamp || "Unknown"}`;
}).join("\n\n");

// Combine all behaviors
const behaviorsText = (data.behaviors || (data.behavior ? [data.behavior] : []))
  .map(b => `- ${b}`)
  .join("\n") || "None";

// Flatten MITRE techniques
const mitreText = (data.mitre || []).flatMap(m => m.mitre || []).map(m => 
  `${m.attack_id} - ${m.name} (${m.tactic.join(", ")})`
).join("\n") || "None";

// Build final LLM input
const reportForLLM = `
Events:
${eventsText}

Observed Behaviors:
${behaviorsText}

Relevant MITRE Techniques:
${mitreText}
`;

return [{
  json: {
    report_text: reportForLLM
  }
}];

const text = $json.text || $json.output || $json.response || $json.llm_output || "";

const descriptionMatch = text.match(
  /Description of Events:\s*([\s\S]*?)(?:Remediation Steps:|$)/
);

const remediationMatch = text.match(
  /Remediation Steps:\s*([\s\S]*)/
);

const description = descriptionMatch ? descriptionMatch[1].trim() : "Not Provided";
const remediation = remediationMatch ? remediationMatch[1].trim() : "Not Provided";

return [{
  json: {
    description,
    remediation
  }
}];

const data = $json;

//Report Sections
const ips = data.ips?.length ? data.ips.join(", ") : "Not Provided";
const users = data.users?.length ? data.users.join(", ") : "Not Provided";

// Human-readable date
const earliestRaw = data.earliest;
const earliest = earliestRaw
  ? new Date(earliestRaw).toLocaleString("en-US", {
      weekday: "short",
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit"
    })
  : "Not Provided";

// LLM output
const description = data.description || "Not Provided";
const remediation = data.remediation || "Not Provided";

//Behaviors
const behaviorsArray = data.behaviors || [];

const behaviors = behaviorsArray.length
  ? behaviorsArray.map((b, i) => `${i+1}. ${b.behavior}`).join("\n")
  : "Not Provided";

//Mitre Techniques, Grouped by Behavior
const mitreSet = new Map();

for (const b of behaviorsArray) {
  for (const m of (b.mitre || [])) {
    if (m.attack_id && !mitreSet.has(m.attack_id)) {
      mitreSet.set(m.attack_id, `${m.attack_id} - ${m.name}`);
    }
  }
}

const mitre = mitreSet.size
  ? Array.from(mitreSet.values()).map((m, i) => `${i+1}. ${m}`).join("\n")
  : "Not Found";

//Mitre Details per Behavior
const mitreByBehavior = behaviorsArray.length
  ? behaviorsArray.map((b, i) => {
      const techniques = (b.mitre || [])
        .map(m => `${m.attack_id} - ${m.name}`)
        .join(", ") || "None";

      return `${i+1}. ${b.behavior}\n   Techniques: ${techniques}`;
    }).join("\n\n")
  : "Not Provided";

// Events
const events = data.events?.length
  ? data.events.map((e, i) => {
      const timestamp = e.timestamp_human || e.timestamp || "Not Provided";
      const eventType = e.event_type || "Not Provided";

      const details = e.details
        || (e.expert_messages?.map(m =>
            `${m.message} (sev ${m.severity_normalized})`
          ).join("; "))
        || "Not Provided";

      return `${i+1}. ${timestamp} | ${eventType} | ${details}`;
    }).join("\n")
  : "Not Provided";

//Appendix A: Key Events
const appendixA = data.key_events?.length
  ? data.key_events.map((ke, i) => `${i+1}. ${ke}`).join("\n")
  : "Not Provided";

//Filename
const original_filename =
  data.original_filename ||
  data.events?.[0]?.original_filename ||
  "Not Provided";

//Final Report
const report_text = `
Incident Report

Reporter Information:
Name: Not Provided
Title: Cybersecurity Incident Investigation Assistant
Report Date: ${new Date().toLocaleString()}
Incident Number: Not Provided
Log Analyzed: ${original_filename}

Incident Overview:
Date of Incident: ${earliest}
Type: Not Provided
Impact Level: Not Provided

Network Details:
Attacker IP Address(es): ${ips}
Victim User(s): ${users}

Behavior-to-Technique Mapping:
${mitreByBehavior}

Description of Events:
${description}

Remediation Steps:
${remediation}

Appendix A: Key Events
${appendixA}
`;

return [{
  json: {
    report_text,
    original_filename
  }
}];

const all = $input.all();

return [{
  json: {
    mitre: all.map(item => item.json)
  }
}];

const mitreItems = $json.mitre || [];

const behaviorMap = new Map();

// Loop over each Mitre item
for (const item of mitreItems) {
  const behaviorName = item.behavior || "Unknown Behavior";

  // If behavior not yet in map, add it
  if (!behaviorMap.has(behaviorName)) {
    behaviorMap.set(behaviorName, {
      behavior: behaviorName,
      mitre: []
    });
  }

  // Push the Mitre technique under the correct behavior
  behaviorMap.get(behaviorName).mitre.push({
    attack_id: item.attack_id,
    name: item.name,
    tactic: item.tactic,
    content: item.content
  });
}

// Convert map values to array
const groupedBehaviors = Array.from(behaviorMap.values());

return [{
  json: {
    behaviors: groupedBehaviors
  }
}];

const behaviors = $json.behaviors || $json.events?.map(e => e.event_type) || [];

const simplifiedBehaviors = behaviors.map(b => {
  // Remove IP addresses
  let s = b.replace(/\b\d{1,3}(?:\.\d{1,3}){3}\b/g, "");
  // Remove ports
  s = s.replace(/port\s+\d+/gi, "");
  // Remove extra whitespace
  s = s.replace(/\s+/g, " ").trim();
  return s;
});

// Deduplicate
const uniqueBehaviors = [...new Set(simplifiedBehaviors)];

return [{
  json: {
    behaviors: uniqueBehaviors
  }
}];

const raw = $json.fileContent || $json.data || $json.body || $json;

let rawFilename = "unknown_file";
if (Array.isArray($json.data) && $json.data[0]?.filename) {
  rawFilename = $json.data[0].filename;
}

const originalFilename = rawFilename.replace(/\.[^/.]+$/, "");

const packets = Array.isArray(raw) ? raw : JSON.parse(raw);

//Parse protocols
function parseProtocols(p) {
  const raw = p["frame.protocols"] || "";

  const parts = raw.split(":");

  // Detect anomalies
  const rawLength = parts.length;
  const uniqueCount = new Set(parts).size;
  const duplicationRatio = uniqueCount / (rawLength || 1);

  const noiseSet = new Set([
    "x509sat",
    "x509ce",
    "pkcs-1",
    "pkix1implicit",
    "pkix1explicit"
  ]);

  const hasNoise = parts.some(x => noiseSet.has(x));

  const anomaly =
    rawLength > 20 ||
    duplicationRatio < 0.5 ||
    hasNoise;

  // Clean the stack
  const IGNORE = new Set([
    "eth",
    "ethertype",
    "x509sat",
    "x509ce",
    "pkix1implicit",
    "pkix1explicit"
  ]);

  const cleaned = parts.filter(p => !IGNORE.has(p));

  // Remove duplicates
  const seen = new Set();
  const protoChain = [];

  for (const p of cleaned) {
    if (!seen.has(p)) {
      seen.add(p);
      protoChain.push(p);
    }
  }

  // Cap the depth of protocols
  const capped = protoChain.slice(0, 6);

  // transport detection
  const transport =
    capped.includes("tcp") ? "tcp" :
    capped.includes("udp") ? "udp" :
    capped.includes("icmp") ? "icmp" :
    "unknown";

  // application detection
  const appList = [
  "http", "http2",
  "dns",
  "tls",
  "ntp",
  "ldap",
  "dhcp",
  "quic",
  "ssl"
];
  const application = capped.find(x => appList.includes(x)) || null;

  return {
    protoChain: capped,
    transport,
    application,
    anomaly,
    raw: raw
  };
}

//Main parser
const parsed = packets.map(p => {

  const epoch = parseFloat(p["frame.time_epoch"] || 0);

  const { protoChain, transport, application, anomaly } = parseProtocols(p);

 //TCP Flags
  const flags = parseInt(p["tcp.flags"] || "0", 16);

  const isSyn = (flags & 0x02) !== 0;
  const isFin = (flags & 0x01) !== 0;
  const isRst = (flags & 0x04) !== 0;

  //Flow Key
  const flow_key =
    `${p["ip.src"]}:${p["tcp.srcport"] || p["udp.srcport"] || 0}` +
    `→${p["ip.dst"]}:${p["tcp.dstport"] || p["udp.dstport"] || 0}`;

  return {
    json: {
      original_filename: originalFilename,

      epoch,
      timestamp_human: epoch
        ? new Date(epoch * 1000).toISOString()
        : null,

      src_ip: p["ip.src"] || null,
      dst_ip: p["ip.dst"] || null,

      src_port: p["tcp.srcport"] || p["udp.srcport"] || "",
      dst_port: p["tcp.dstport"] || p["udp.dstport"] || "",

      protocol: transport,
      application_protocol: application,
      protocol_stack: protoChain,
      "protocol.anomaly": anomaly,

      flow_key,

      is_syn: isSyn,
      is_fin: isFin,
      is_rst: isRst,

      event_type:
        transport !== "tcp"
          ? "non_tcp"
          : isSyn
          ? "connection_start"
          : isFin
          ? "connection_end"
          : isRst
          ? "connection_reset"
          : "unknown",

      expert_messages: []
    }
  };
});

return parsed;

const chunkSize = 500;
const data = $input.all();

let chunks = [];
for (let i = 0; i < data.length; i += chunkSize) {
  chunks.push(data.slice(i, i + chunkSize));
}

return chunks.map(chunk => ({ json: { chunk } }));

let allIPs = new Set();
let allUsers = new Set();
let allPorts = new Set();
let allFlags = new Set();
let allEventTypes = new Set();
let allEvents = [];
let totalFlagCounts = { syn: 0, fin: 0, rst: 0 };
let totalSeverityCounts = {};
let totalGroupCounts = {};
let topExperts = []; // new array to hold top expert messages

for (const item of $input.all()) {
  (item.json.ips || []).forEach(ip => allIPs.add(ip));
  (item.json.users || []).forEach(u => allUsers.add(u));
  (item.json.ports || []).forEach(p => allPorts.add(p));
  (item.json.flags || []).forEach(f => allFlags.add(f));
  (item.json.event_types || []).forEach(e => allEventTypes.add(e));

  const flagCounts = item.json.flag_counts || {};
  totalFlagCounts.syn += flagCounts.syn || 0;
  totalFlagCounts.fin += flagCounts.fin || 0;
  totalFlagCounts.rst += flagCounts.rst || 0;

  const severityCounts = item.json.severity_counts || {};
  for (const sev in severityCounts) {
    totalSeverityCounts[sev] = (totalSeverityCounts[sev] || 0) + severityCounts[sev];
  }

  const groupCounts = item.json.group_counts || {};
  for (const group in groupCounts) {
    totalGroupCounts[group] = (totalGroupCounts[group] || 0) + groupCounts[group];
  }

  const events = item.json.events || [];
  allEvents.push(...events);

  // Track top experts
  events.forEach(ev => {
    (ev.expert_messages || []).forEach(msg => {
      if (!topExperts.some(e => e.message === msg.message && e.flag === msg.flag)) {
        topExperts.push({
          flag: msg.flag,
          message: msg.message,
          severity_normalized: msg.severity_normalized,
          group_label: msg.group_label
        });
      }
    });
  });
}

// Sort events by timestamp
allEvents.sort((a,b) => new Date(a.timestamp) - new Date(b.timestamp));

// Sort topExperts by severity descending
topExperts.sort((a,b) => b.severity_normalized - a.severity_normalized);

return [{
  json: {
    ips: [...allIPs],
    users: [...allUsers],
    ports: [...allPorts],
    flags: [...allFlags],
    event_types: [...allEventTypes],
    flag_counts: totalFlagCounts,
    severity_counts: totalSeverityCounts,
    group_counts: totalGroupCounts,
    events: allEvents,
    top_expert_messages: topExperts,
    earliest: allEvents[0]?.timestamp_human || "Not Provided"
  }
}];
